# DK FBM.  Funder - Bramming
#
let fb = path("d3.dk.fbm");

with detail = 3, railway = :first :pax :removed {
    # point.dk.Funder  dk.SBS

    with link = "line.dk.FBM" {
        track(:lor, fb[:fun + 0.49sw, :fun.yb] >> 1ms >> 1mt);
        track(:lor :casing,
                fb[:fun.yb - 0.1dl, :fun.xb] >> 1ms >> 1mt
            ..  fb[:fun.zb, :fun.zb + 0.1dl]
        );
        track(fb[:fun.zb, :fun.zb + 1.01km]);
        line_label(:right:e, fb[:fun.zb + 1km] >> 0.5mt, "FBM");
        track(fb[:fun.zb + 0.99km, :chr - 0.49sw]);
    }

    with link = "point.dk.Christianshede", railway = :station {
        track(fb[:chr - 0.5sw, :chr + 0.5sw]);
        marker(:right :de.bf, fb[:chr] >> 0.5mt);
        slabel(:left, fb[:chr] >> 0.5mt >> 1sh + (-1.5dt, 0.6dt),
            "Christianshede"
        );
    }

    with link = "line.dk.FBM" {
        track(fb[:chr + 0.49sw, :seb]);
    }

    with link = "point.dk.Sebstrup", railway = :station {
        marker(:left :de.anst, fb[:seb] << 0.5mt);
        slabel(:right :xsmall, fb[:seb] << 0.5mt << 1sh + (1.3dt, 1dt),
            "Sebstrup"
        );
    }

    with link = "line.dk.FBM" {
        track(fb[:seb, :hjo - 0.49sw]);
    }

    with link = "point.dk.Hjøllund", railway = :station {
        track(fb[:hjo - 0.5sw, :hjo + 0.5sw]);
        marker(:left :de.hst, fb[:hjo] << 0.5mt);
        slabel(:right, fb[:hjo] << 0.5mt << 1sh + (1.3dt, 1.2dt),
            "Hjøllund"
        );
    }

    with link = "line.dk.FBM" {
        track(fb[:hjo + 0.49sw, :ham - 0.49sw]);
    }

    with link = "point.dk.Hampen", railway = :station {
        track(fb[:ham - 0.5sw, :ham + 0.5sw]);
        marker(:right :de.bf, fb[:ham] >> 0.5mt);
        slabel(:left, fb[:ham] >> 0.5mt >> 1sh + (-1.5dt, 0.6dt),
            "Hampen"
        );
    }

    with link = "line.dk.FBM" {
        track(fb[:ham + 0.49sw, :ham + 4.01km]);
        line_label(:right:se, fb[:ham + 4km] >> 0.5mt, "FBM");
        track(fb[:ham + 3.99km, :ejs.yr - 0.49seg]);
    }

    with link = "point.dk.Ejstrupholm", railway = :station {
        track(
                fb[:ejs.yr, :ejs + 0.5sw] << 1ms << 1mt
            --  fb[:ejs + 0.5sw + 1dl, :ejs + 0.5sw + 1.1dl]
        );
        track(fb[:ejs.yr - 0.5seg, :ejs + 0.5sw + 2dl]);
        marker(:right :de.bf, fb[:ejs] >> 0.5mt);
        slabel(:top :bold, fb[:ejs] >> 0.5mt >> 1sh + (-3.5dt, -0.3dt),
            "Ejstrupholm"
        );
    }

    with link = "line.dk.FBM" {
        track(fb[:ejs + 0.49sw, :lun - 0.49sw]);
    }

    with link = "point.dk.Lundfod", railway = :station {
        track(fb[:lun - 0.5sw, :lun + 0.5sw]);
        marker(:left :de.hst, fb[:lun] << 0.5mt);
        slabel(:bottom, fb[:lun] << 0.5mt << 1sh << 0.3dt,
            "Lundfod"
        );
    }

    with link = "line.dk.FBM" {
        track(fb[:lun + 0.49sw, :lun + 3.01km]);
        line_label(:right:s, fb[:lun + 3km] >> 0.5mt, "FBM");
        track(fb[:lun + 2.99km, :brd.xf]);
        track(:ror,
                fb[:brd.xf - 0.1dl, :brd.xf]
            ..  fb[:brd.yf, :brd.yf + 0.1dl] << 1ms << 1mt
        );
        track(:ror, fb[:brd.yf, :brd - 549m] << 1ms << 1mt);
    }

    # point.dk.Brande  dk.HBV

    with link = "line.dk.FBM" {
        track(:station, fb[:brd.yb, :brd.xb] >> 1ms >> 1mt);
        track(
                fb[:brd.xb - 0.1dl, :brd.xb] >> 1ms >> 1mt
            ..  fb[:brd.zb + 1mt, :brd.zb + 1.31km]
        );
        line_label(:left:nw, fb[:brd.zb + 1.3km] << 0.5mt, "FBM");
        track(fb[:brd.zb + 1.29km, :dra - 0.49sw]);
    }

    with link = "point.dk.Drantum", railway = :station {
        track(fb[:dra - 0.5sw, :dra + 0.5sw]);
        marker(:right :de.hst, fb[:dra] >> 0.5mt);
        slabel(:left, fb[:dra] >> 0.5mt >> 1sh + (-1.5dt, 0.3dt),
            "Drantum"
        );
    }

    with link = "line.dk.FBM" {
        track(fb[:dra + 0.49sw, :bla - 0.49sw]);
    }

    with link = "point.dk.Blåhøj", railway = :station {
        track(fb[:bla - 0.5sw, :bla + 0.5sw]);
        marker(:right :de.bf, fb[:bla] >> 0.5mt);
        slabel(:left, fb[:bla] >> 0.5mt >> 1sh + (-1.5dt, 0.3dt),
            "Blåhøj"
        );
    }

    with link = "line.dk.FBM" {
        track(fb[:bla + 0.49sw, :hal - 0.49sw]);
    }

    with link = "point.dk.Hallundbæk", railway = :station {
        track(fb[:hal - 0.5sw, :hal + 0.5sw]);
        marker(:right :de.hp, fb[:hal] >> 0.5mt);
        slabel(:left, fb[:hal] >> 0.5mt >> 1sh + (-1.3dt, 1.1dt),
            "Hallundbæk"
        );
    }

    with link = "line.dk.FBM" {
        track(fb[:hal + 0.49sw, :fil - 0.49sw]);
    }

    with link = "point.dk.Filskov", railway = :station {
        track(fb[:fil - 0.5sw, :fil + 0.5sw]);
        marker(:left :de.bf, fb[:fil] << 0.5mt);
        slabel(:right, fb[:fil] << 0.5mt << 1sh + (1.4dt, 1.3dt),
            "Filskov"
        );
    }

    with link = "line.dk.FBM" {
        track(fb[:fil + 0.49sw, :kol - 0.49sw]);
    }

    with link = "point.dk.Kolstrupgård", railway = :station {
        track(fb[:kol - 0.5sw, :kol + 0.5sw]);
        marker(:right :de.hp, fb[:kol] >> 0.5mt);
        slabel(:top, fb[:kol] >> 0.5mt >> 1sh + (-5dt, -0.5dt),
            "Kolstrupgård"
        );
    }

    with link = "line.dk.FBM" {
        track(fb[:kol + 0.49sw, :kol + 1.61km]);
        line_label(:left:nw, fb[:kol + 1.6km] << 0.5mt, "FBM");
        track(fb[:kol + 1.59km, :gri.zf]);
        with layer = -1 track(
                fb[:gri.zf - 0.1dl, :gri.zf]
            ..  fb[:gri.yf - 0.5seg, :gri.yf - 0.49seg] >> 1ms >> 1mt
        );
        track(:station, fb[:gri.yf - 0.5seg, :gri.yf] >> 1ms >> 1mt);
    }

    # point.dk.Grindsted  dk.THK
}

with detail = 3, railway = :first :pax :closed {
    with link = "line.dk.FBM" {
        track(:lor,
                fb[:gri.yb - 0.1dl, :gri.yb + 0.5seg] >> 1ms >> 1mt
        );
        track(
                fb[:gri.yb + 0.49seg, :gri.yb + 0.5seg] >> 1ms >> 1mt
            ..  fb[:gri.xb, :gri.xb + 0.1dl]
        );
        track(fb[:gri.xb, :gri.xb + 1.21km]);
        line_label(:right:se, fb[:gri.xb + 1.2km] >> 0.5mt, "FBM");
        track(fb[:gri.xb + 1.19km, :hor - 0.49sw]);
    }

    with link = "point.dk.Horsbøl", railway = :station {
        track(fb[:hor - 0.5sw, :hor + 0.5sw]);
        marker(:right :de.hp :removed, fb[:hor] >> 0.5mt);
        slabel(:left :removed, fb[:hor] >> 0.5mt >> 1sh + (-1.7dt, 0.6dt),
            "Horsbøl"
        );
    }

    with link = "line.dk.FBM" {
        track(fb[:hor + 0.49sw, :kro - 0.49sw]);
    }

    with link = "point.dk.Krogager", railway = :station {
        track(fb[:kro - 0.5sw, :kro + 0.5sw]);
        marker(:right :de.bf :removed, fb[:kro] >> 0.5mt);
        slabel(:left :removed, fb[:kro] >> 0.5mt >> 1sh + (-1.4dt, 0.7dt),
            "Krogager"
        );
    }

    with link = "line.dk.FBM" {
        track(fb[:kro + 0.49sw, :tof - 0.49sw]);
    }

    with link = "point.dk.Tofterup", railway = :station {
        track(fb[:tof - 0.5sw, :tof + 0.5sw]);
        marker(:right :de.bf :removed, fb[:tof] >> 0.5mt);
        slabel(:left :removed, fb[:tof] >> 0.5mt >> 1sh + (-1.4dt, 0.9dt),
            "Tofterup"
        );
    }

    with link = "line.dk.FBM" {
        track(fb[:tof + 0.49sw, :age - 0.49sw]);
    }

    with link = "point.dk.Agerbæk", railway = :station {
        track(fb[:age - 0.5sw, :age + 0.5sw]);
        marker(:right :de.bf :removed, fb[:age] >> 0.5mt);
        slabel(:left :removed, fb[:age] >> 0.5mt >> 1sh + (-1.5dt, 0.7dt),
            "Agerbæk"
        );
    }

    with link = "line.dk.FBM" {
        track(fb[:age + 0.49sw, :age + 2.31km]);
        line_label(:left:sw, fb[:age + 2.3km] << 0.5mt, "FBM");
        track(fb[:age + 2.29km, :gle - 0.49sw]);
    }

    with link = "point.dk.Glejbjerg", railway = :station {
        track(fb[:gle - 0.5sw, :gle + 0.5sw]);
        marker(:left :de.bf :removed, fb[:gle] << 0.5mt);
        slabel(:right :removed, fb[:gle] << 0.5mt << 1sh + (1.3dt, 1.1dt),
            "Glejbjerg"
        );
    }

    with link = "line.dk.FBM" {
        track(fb[:gle + 0.49sw, :vej - 0.49sw]);
    }

    with link = "point.dk.Vejrup", railway = :station {
        track(fb[:vej - 0.5sw, :vej + 0.5sw]);
        marker(:right :de.bf :removed, fb[:vej] >> 0.5mt);
        slabel(:left :removed, fb[:vej] >> 0.5mt >> 1sh + (-1.7dt, 0.2dt),
            "Vejrup"
        );
    }

    with link = "line.dk.FBM" {
        track(fb[:vej + 0.49sw, :vbj - 0.49sw]);
    }

    with link = "point.dk.Vester-Bjerndrup", railway = :station {
        track(fb[:vbj - 0.5sw, :vbj + 0.5sw]);
        marker(:right :de.hp :removed, fb[:vbj] >> 0.5mt);
        slabel(:left :removed, fb[:vbj] >> 0.5mt >> 1sh + (-1.3dt, 0.9dt),
            "Vester Bjerndrup"
        );
    }

    with link = "line.dk.FBM" {
        track(fb[:vbj + 0.49sw, :vbj + 2.81km]);
        line_label(:right:se, fb[:vbj + 2.8km] >> 0.5mt, "FBM");
        track(fb[:vbj + 2.79km, :bra.xf - 1md]);
        track(:lor,
                fb[:bra.xf - 1.01md, :bra.xf - 1md]
            ..  fb[:bra.yf, :bra.yf + 0.1dl] >> 0.5md >> 1ms >> 0.5mt
        );
        track(:lor :removed, fb[:bra.yf, :bra.yt] >> 0.5md >> 1ms >> 0.5mt);
    }
}

